```python
class BinaryTreeNode:
    def __init__(self, value):
        self.value = value
        self.left = None
        self.right = None

def build_tree(n):
    if n == 0:
        return None
    root = BinaryTreeNode(n)
    root.left = build_tree(n - 1)
    root.right = build_tree(n - 1)
    return root

def inorder(node):
    if node:
        inorder(node.left)
        print(node.value)
        inorder(node.right)

def preorder(node):
